+    local procedure ConvertAmountToJobCurrency(Amount: Decimal; GenJnlLine: Record "Gen. Journal Line"): Decimal
+    var
+        JobCurrency: Record Currency;
+        OverallCurrencyFactor: Decimal;
+    begin
+        if GenJnlLine."Currency Factor" = 0 then begin
+            if GenJnlLine."Job Currency Factor" = 0 then
+                OverallCurrencyFactor := 1
+            else
+                OverallCurrencyFactor := GenJnlLine."Job Currency Factor";
+        end else
+            if GenJnlLine."Job Currency Factor" = 0 then
+                OverallCurrencyFactor := 1 / GenJnlLine."Currency Factor"
+            else
+                OverallCurrencyFactor := GenJnlLine."Job Currency Factor" / GenJnlLine."Currency Factor";
+
+        if GenJnlLine."Job Currency Code" = '' then
+            JobCurrency.InitRoundingPrecision()
+        else begin
+            JobCurrency.Get(GenJnlLine."Job Currency Code");
+            JobCurrency.TestField("Amount Rounding Precision");
+        end;
+
+        exit(Round(Amount * OverallCurrencyFactor, JobCurrency."Amount Rounding Precision"));
+    end;
